#!/usr/bin/env python3
import json, os, sys, math, collections
from pathlib import Path
sys.path.insert(0, str(Path(__file__).resolve().parent))
from cost_model import CostModel, HEADS, HIDDEN, align

ROOT = Path('/app/task_file')
GRAN = 64
MAX_SHAPES = 8
CM = CostModel(GRAN)

def load(path):
    return [json.loads(l) for l in open(path)]

def save(path, recs):
    os.makedirs(os.path.dirname(path), exist_ok=True)
    with open(path, 'w') as f:
        for r in recs:
            f.write(json.dumps(r) + '\n')

def shape_compile_cost(s):
    return CM.c.Kshape_attn * (s ** 2) + CM.c.Kshape_mlp * (s * HIDDEN)

def prefill_cost(p):
    return CM._prefill_cost(p)

def prefill_lat(p):
    return CM._prefill_lat(p)

def decode_cost_for(s, g):
    A = CM.c.Kd_attn
    B = CM.c.Kd_mlp * HIDDEN
    sum_sq = CM._sum_sq_arith(s, g)
    sum_lin = g * s + g * (g - 1) / 2
    return A * sum_sq + B * sum_lin

def decode_lat_for(s, g):
    A = CM.c.Td_attn
    B = CM.c.Td_mlp * HIDDEN
    sum_sq = CM._sum_sq_arith(s, g)
    sum_lin = g * s + g * (g - 1) / 2
    return A * sum_sq + B * sum_lin

def choose_shapes(reqs, k):
    uniq = sorted(set(align(r['prompt_len'], GRAN) for r in reqs))
    weights = {s: 0 for s in uniq}
    for r in reqs:
        weights[align(r['prompt_len'], GRAN)] += 1
    from itertools import combinations
    best = None
    for kk in range(1, min(k, len(uniq)) + 1):
        for combo in combinations(uniq, kk):
            reps = sorted(combo)
            if reps[-1] != uniq[-1]:
                continue
            pad = 0
            for r in reqs:
                rep = reps[-1]
                for x in reps:
                    if x >= align(r['prompt_len'], GRAN):
                        rep = x
                        break
                pad += rep - r['prompt_len']
            score = pad + sum(shape_compile_cost(s) / 1e8 for s in reps)
            if best is None or score < best[0]:
                best = (score, reps)
    if best is None:
        return uniq[-1:]
    return best[1]

def assign_shape(reqs, reps):
    out = []
    for r in reqs:
        s = align(r['prompt_len'], GRAN)
        rep = reps[-1]
        for x in reps:
            if x >= s:
                rep = x
                break
        rr = dict(r)
        rr['shape_seq'] = rep
        out.append(rr)
    return out

def partition_shape(reqs, pad_penalty=2e5, max_batch=200):
    rs = sorted(reqs, key=lambda r: (r['gen_len'], r['prompt_len']))
    n = len(rs)
    if n == 0:
        return []
    pc = [prefill_cost(r['prompt_len']) for r in rs]
    pl = [prefill_lat(r['prompt_len']) for r in rs]
    ppad = [align(r['prompt_len'], GRAN) - r['prompt_len'] for r in rs]
    def seg_cost(i, j):
        sub = rs[i:j]
        g = max(r['gen_len'] for r in sub)
        s = max(align(r['prompt_len'], GRAN) for r in sub)
        dc = decode_cost_for(s, g)
        dl = decode_lat_for(s, g)
        cost = sum(pc[i:j]) + len(sub) * dc + CM.c.Kbatch_overhead_cost
        pad = sum(ppad[i:j]) + sum(g - r['gen_len'] for r in sub)
        max_lat = max(pl[i:j]) + dl + CM.c.Tbatch_overhead_ms
        return cost, pad, max_lat
    dp = [float('inf')] * (n + 1)
    par = [-1] * (n + 1)
    dp[0] = 0.0
    for j in range(1, n + 1):
        for i in range(max(0, j - max_batch), j):
            c, pad, lat = seg_cost(i, j)
            val = dp[i] + c + pad_penalty * pad
            if val < dp[j]:
                dp[j] = val
                par[j] = i
    parts = []
    j = n
    while j > 0:
        i = par[j]
        parts.append((i, j))
        j = i
    parts.reverse()
    return parts

def build_bucket(reqs, max_shapes):
    reps = choose_shapes(reqs, max_shapes)
    assigned = assign_shape(reqs, reps)
    by_shape = collections.defaultdict(list)
    for r in assigned:
        by_shape[r['shape_seq']].append(r)
    recs = []
    bid = 0
    for s in sorted(by_shape):
        parts = partition_shape(by_shape[s])
        for i, j in parts:
            bid += 1
            batch_id = f'b{bid:04d}'
            for r in by_shape[s][i:j]:
                recs.append({
                    'request_id': r['request_id'],
                    'batch_id': batch_id,
                    'shape': {'seq_align': s, 'heads_align': HEADS, 'hidden_align': HIDDEN}
                })
    return recs

def main():
    b1 = load(str(ROOT / 'input_data' / 'requests_bucket_1.jsonl'))
    b2 = load(str(ROOT / 'input_data' / 'requests_bucket_2.jsonl'))
    # split global shape budget; b1 dominates prompt range, b2 smaller
    reps1 = choose_shapes(b1, 6)
    reps2 = choose_shapes(b2, MAX_SHAPES - len(reps1))
    plan1 = build_bucket_with_reps(b1, reps1)
    plan2 = build_bucket_with_reps(b2, reps2)
    save(str(ROOT / 'output_data' / 'plan_b1.jsonl'), plan1)
    save(str(ROOT / 'output_data' / 'plan_b2.jsonl'), plan2)

def build_bucket_with_reps(reqs, reps):
    assigned = assign_shape(reqs, reps)
    by_shape = collections.defaultdict(list)
    for r in assigned:
        by_shape[r['shape_seq']].append(r)
    recs = []
    bid = 0
    for s in sorted(by_shape):
        parts = partition_shape(by_shape[s])
        for i, j in parts:
            bid += 1
            batch_id = f'b{bid:04d}'
            for r in by_shape[s][i:j]:
                recs.append({
                    'request_id': r['request_id'],
                    'batch_id': batch_id,
                    'shape': {'seq_align': s, 'heads_align': HEADS, 'hidden_align': HIDDEN}
                })
    return recs

if __name__ == '__main__':
    main()
